import io.grpc.*;
import io.grpc.stub.*;
import java.io.*;
import java.util.concurrent.*;
import java.util.logging.*;

public class FileTransferService extends FileTransferGrpc.FileTransferImplBase {
    private static final Logger logger = Logger.getLogger(FileTransferService.class.getName());
    private static final int CHUNK_SIZE = 1024 * 1024; // 1MB chunks

    @Override
    public StreamObserver<TransferRequest> transferData(StreamObserver<TransferResponse> responseObserver) {
        return new StreamObserver<TransferRequest>() {
            private ByteArrayOutputStream buffer = new ByteArrayOutputStream();
            private String fileName = "";
            private long totalBytes = 0;
            private boolean isFinished = false;

            @Override
            public void onNext(TransferRequest request) {
                try {
                    if (request.hasFileInfo()) {
                        fileName = request.getFileInfo().getFileName();
                        totalBytes = request.getFileInfo().getFileSize();
                    } else if (request.hasData()) {
                        buffer.write(request.getData().toByteArray());
                    }
                    
                    responseObserver.onNext(TransferResponse.newBuilder()
                            .setProgress(buffer.size())
                            .setTotal(totalBytes)
                            .build());
                } catch (Exception e) {
                    logger.log(Level.SEVERE, "Error processing data chunk", e);
                    responseObserver.onError(Status.INTERNAL.withDescription("Processing error").asException());
                }
            }

            @Override
            public void onError(Throwable t) {
                logger.log(Level.SEVERE, "Error in transfer stream", t);
                responseObserver.onCompleted();
            }

            @Override
            public void onCompleted() {
                try {
                    if (buffer.size() > 0) {
                        // Save file or process data
                        saveFile(buffer.toByteArray(), fileName);
                    }
                    responseObserver.onNext(TransferResponse.newBuilder()
                            .setSuccess(true)
                            .setMessage("Transfer completed successfully")
                            .build());
                } catch (Exception e) {
                    logger.log(Level.SEVERE, "Error completing transfer", e);
                    responseObserver.onError(Status.INTERNAL.withDescription("Transfer failed").asException());
                } finally {
                    responseObserver.onCompleted();
                }
            }
        };
    }

    @Override
    public void uploadFile(TransferRequest request, StreamObserver<TransferResponse> responseObserver) {
        try {
            if (request.hasFileInfo()) {
                String fileName = request.getFileInfo().getFileName();
                long fileSize = request.getFileInfo().getFileSize();
                
                // Create file upload stream
                FileUploadStream uploadStream = new FileUploadStream(fileName, fileSize);
                
                if (request.hasData()) {
                    uploadStream.write(request.getData().toByteArray());
                }
                
                responseObserver.onNext(TransferResponse.newBuilder()
                        .setSuccess(true)
                        .setMessage("File upload started")
                        .build());
            }
        } catch (Exception e) {
            logger.log(Level.SEVERE, "Error uploading file", e);
            responseObserver.onError(Status.INTERNAL.withDescription("Upload failed").asException());
        }
    }

    private void saveFile(byte[] data, String fileName) throws IOException {
        try (FileOutputStream fos = new FileOutputStream(fileName)) {
            fos.write(data);
        }
    }

    public static class FileUploadStream {
        private final String fileName;
        private final long totalSize;
        private final ByteArrayOutputStream buffer;
        private long uploadedBytes = 0;

        public FileUploadStream(String fileName, long totalSize) {
            this.fileName = fileName;
            this.totalSize = totalSize;
            this.buffer = new ByteArrayOutputStream();
        }

        public void write(byte[] data) throws IOException {
            buffer.write(data);
            uploadedBytes += data.length;
        }

        public void complete() throws IOException {
            try (FileOutputStream fos = new FileOutputStream(fileName)) {
                buffer.writeTo(fos);
            }
        }
    }
}